const b = ($input.first().json.body) || {};
let raw = (b.text !== undefined && b.text !== null) ? b.text : ((b.prompt !== undefined && b.prompt !== null) ? b.prompt : '');
raw = String(raw);
const original_length = raw.length;
// L2: strip ASCII control chars (keep \t \n \r), NFC-normalize, collapse whitespace, cap 2000.
let s = raw.replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F\u007F]/g, '');
s = s.normalize('NFC');
s = s.replace(/\s+/g, ' ').trim();
if (s.length > 2000) { s = s.slice(0, 2000); }
return [{ json: { sanitized: s, original_length: original_length } }];

// Parse the classifier's raw JSON text robustly (no throwing output-parser):
// any parse failure -> intent 'unknown' (graceful; OWASP LLM01 bounded refusal).
// Also re-attach the sanitized text, which the chain node drops from the item.
const cls = $input.first().json;
const sanitized = $('Sanitize Input').first().json.sanitized;
let intent = 'unknown';
let confidence = 0;
let entity_mention = null;
try {
  let parsed = null;
  if (cls.output && typeof cls.output === 'object') {
    parsed = cls.output;
  } else {
    const raw = String(cls.text != null ? cls.text : (cls.response != null ? cls.response : (cls.output != null ? cls.output : '')));
    const m = raw.match(/\{[\s\S]*\}/);
    if (m) { parsed = JSON.parse(m[0]); }
  }
  if (parsed && typeof parsed === 'object') {
    if (typeof parsed.intent === 'string') { intent = parsed.intent.toLowerCase().trim(); }
    const c = (typeof parsed.confidence === 'number') ? parsed.confidence : Number(parsed.confidence);
    if (c >= 0 && c <= 1) { confidence = c; }
    if (typeof parsed.entity_mention === 'string' && parsed.entity_mention.trim()) { entity_mention = parsed.entity_mention.trim(); }
  }
} catch (e) { intent = 'unknown'; confidence = 0; entity_mention = null; }
const allowed = ['ops', 'code', 'research', 'infra', 'unknown'];
if (allowed.indexOf(intent) === -1) { intent = 'unknown'; }
return [{ json: { sanitized: sanitized, intent: intent, confidence: confidence, entity_mention: entity_mention } }];

// Resolve a possibly-imprecise file mention to a REAL path from the catalog,
// deterministically (no LLM guessing). Zero-dependency Jaro-Winkler vs each
// catalog path's basename AND full path, case-insensitive. Reads the dispatch
// fields from Build Dispatch and the catalog from Load Catalog. Graceful: any
// error, no mention, or empty catalog -> gate 'continue' with the dispatch
// unchanged (normal routing). Thresholds per the research synthesis (7.3):
//   >=0.85 auto-resolve (inject verified path) | 0.70-0.84 ask / list candidates
//   <0.70 offer a folder listing. Never gives up, never invents.
const d = $('Build Dispatch').first().json || {};
const sanitized = d.sanitized || '';
const intent = (typeof d.intent === 'string') ? d.intent : 'unknown';
const confidence = (typeof d.confidence === 'number') ? d.confidence : 0;
const mention = (typeof d.entity_mention === 'string') ? d.entity_mention.trim() : '';
const base = { sanitized: sanitized, intent: intent, confidence: confidence, entity_mention: mention || null };
function jaro(a, b) {
  if (a === b) return 1;
  const al = a.length, bl = b.length;
  if (al === 0 || bl === 0) return 0;
  const md = Math.max(0, Math.floor(Math.max(al, bl) / 2) - 1);
  const am = new Array(al).fill(false), bm = new Array(bl).fill(false);
  let matches = 0;
  for (let i = 0; i < al; i++) {
    const lo = Math.max(0, i - md), hi = Math.min(i + md + 1, bl);
    for (let j = lo; j < hi; j++) { if (!bm[j] && a[i] === b[j]) { am[i] = true; bm[j] = true; matches++; break; } }
  }
  if (matches === 0) return 0;
  let tr = 0, k = 0;
  for (let i = 0; i < al; i++) { if (am[i]) { while (!bm[k]) k++; if (a[i] !== b[k]) tr++; k++; } }
  tr = tr / 2;
  return (matches / al + matches / bl + (matches - tr) / matches) / 3;
}
function jw(a, b) {
  const j = jaro(a, b);
  let p = 0; const mx = Math.min(4, Math.min(a.length, b.length));
  while (p < mx && a[p] === b[p]) p++;
  return j + p * 0.1 * (1 - j);
}
try {
  const cat = $('Load Catalog').first().json || {};
  let paths = cat.paths;
  if (typeof paths === 'string') { try { paths = JSON.parse(paths); } catch (e) { paths = []; } }
  if (!Array.isArray(paths)) paths = [];
  if (!mention || paths.length === 0) {
    return [{ json: Object.assign({}, base, { gate: 'continue', resolved: false }) }];
  }
  const q = mention.toLowerCase();
  const scored = [];
  for (let i = 0; i < paths.length; i++) {
    const full = String(paths[i]);
    const bn = full.split('/').pop();
    const sc = Math.max(jw(q, full.toLowerCase()), jw(q, bn.toLowerCase()));
    scored.push({ path: full, score: sc });
  }
  scored.sort(function (x, y) { return y.score - x.score; });
  const best = scored[0];
  const cands = scored.filter(function (x) { return x.score >= 0.70; }).slice(0, 4);
  if (best.score >= 0.85) {
    const note = sanitized + '\n\n[\u05d4\u05de\u05e2\u05e8\u05db\u05ea \u05d0\u05d9\u05de\u05ea\u05d4: \u05d4\u05e0\u05ea\u05d9\u05d1 \u05d4\u05de\u05d3\u05d5\u05d9\u05e7 \u05d4\u05d5\u05d0 "' + best.path + '". \u05e7\u05e8\u05d0 \u05d0\u05d5\u05ea\u05d5 \u05e2\u05dd read_file:' + best.path + '.]';
    return [{ json: { sanitized: note, intent: intent, confidence: confidence, entity_mention: mention, gate: 'continue', resolved: true, resolved_path: best.path, score: best.score } }];
  }
  if (best.score >= 0.70) {
    let reply;
    if (cands.length > 1) {
      let lines = '\u05d4\u05ea\u05db\u05d5\u05d5\u05e0\u05ea \u05dc:';
      for (let i = 0; i < cands.length; i++) { lines += '\n' + (i + 1) + ') ' + cands[i].path; }
      lines += '\n\u05e2\u05e0\u05d4 \u05d1\u05de\u05e1\u05e4\u05e8.';
      reply = lines;
    } else {
      reply = '\u05d4\u05ea\u05db\u05d5\u05d5\u05e0\u05ea \u05dc-`' + best.path + '`? (\u05db\u05df/\u05dc\u05d0)';
    }
    return [{ json: Object.assign({}, base, { gate: 'stop', resolved: false, reply: reply, score: best.score }) }];
  }
  return [{ json: Object.assign({}, base, { gate: 'stop', resolved: false, reply: '\u05dc\u05d0 \u05de\u05e6\u05d0\u05ea\u05d9 \u05e7\u05d5\u05d1\u05e5 \u05e9\u05de\u05ea\u05d0\u05d9\u05dd. \u05e8\u05d5\u05e6\u05d4 \u05e9\u05d0\u05e6\u05d9\u05d2 \u05d0\u05ea \u05ea\u05d5\u05db\u05df \u05d4\u05ea\u05d9\u05e7\u05d9\u05d9\u05d4 \u05d4\u05e8\u05d0\u05e9\u05d9\u05ea? \u05ea\u05df \u05e9\u05dd \u05de\u05d3\u05d5\u05d9\u05e7 \u05d0\u05dd \u05d9\u05e9.', score: best.score }) }];
} catch (e) {
  return [{ json: Object.assign({}, base, { gate: 'continue', resolved: false }) }];
}

// L5 egress validation: reject exec/eval, strip <script>, redact non-allowlisted
// URLs, cap length.
const item = $input.first().json;
let reply = (item.reply !== undefined && item.reply !== null) ? item.reply : ((item.output !== undefined && item.output !== null) ? item.output : '');
reply = String(reply);
if (/exec\s*\(|eval\s*\(/i.test(reply)) {
  return [{ json: { reply: 'Response withheld by egress policy.' } }];
}
reply = reply.replace(/<script[\s\S]*?<\/script>/gi, '').replace(/<\/?script[^>]*>/gi, '');
const ALLOW = /(^|\.)(or-infra\.com|openrouter\.ai|n8n\.io|github\.com|railway\.app|railway\.com)$/i;
reply = reply.replace(/https?:\/\/[^\s<>"')]+/gi, function (u) {
  try { return ALLOW.test(new URL(u).hostname) ? u : '[redacted-url]'; }
  catch (e) { return '[redacted-url]'; }
});
if (reply.length > 4000) { reply = reply.slice(0, 4000); }
return [{ json: { reply: reply } }];
